// sigma0(Prod[pi^ai]) = Prod(ai+1)
// hence to have 4 divisors we need to consider numbers in the form: p^3, pq

#include <stdint.h>
#include <stdbool.h>
#include <assert.h>

#include <stdio.h>
#define __STDC_FORMAT_MACROS
#include <inttypes.h>

#define IMPL_LOWER_BOUND_VTYPE(T, VT, NAME, CMP)                                                \
    static inline int NAME(int n, const T elem[const static n], VT v) {                         \
        int low = 0, high = n;                      /* start with whole array               */  \
        while(high > low) {                         /* more than one candidate              */  \
            const int mid = low + (high - low) / 2; /* pick middle                          */  \
            if(CMP(elem[mid], v))   low = mid + 1;  /* a[mid] <  v: no need to consider mid */  \
            else                    high = mid;     /* a[mid] >= v: pick first half         */  \
        }                                                                                       \
        return low;                                                                             \
    }

#define LESS(a,b) ((a)<(b))
IMPL_LOWER_BOUND_VTYPE(int64_t, int64_t, lower_bound, LESS)

#define SIEVE_MAX_PRIME 99999989
#define SIEVE_PRIME_COUNT 5761455

static bool _sieve_is_composite[SIEVE_MAX_PRIME/2+1] = {}; // 2*i+1
static int64_t _sieve_prime[SIEVE_PRIME_COUNT];

static void generate_primes() {
    // sieve
    _sieve_is_composite[0] = true;
    for(int64_t i = 1, j = 3 ; j*j <= SIEVE_MAX_PRIME ; ++i, j+= 2) {
        if(_sieve_is_composite[i]) continue;
        for(int64_t jj = j*j, ii = (jj-1)/2 ; jj <= SIEVE_MAX_PRIME ; jj += 2*j, ii += j)
            _sieve_is_composite[ii] = true;
    }

    // collect primes
    _sieve_prime[0] = 2;
    for(int64_t i = 0, in = (SIEVE_MAX_PRIME-1)/2, pi = 1 ; i <= in ; ++i) {
        if(_sieve_is_composite[i]) continue;
        assert(pi < SIEVE_PRIME_COUNT); _sieve_prime[pi++] = 2*i+1;
    }
}

static uint64_t isqrt(uint64_t n) {
    uint64_t bit_place = 1ULL << 31;
    while(bit_place > n) bit_place >>= 1;

    uint64_t root = 0; while(bit_place) {
        const uint64_t root_cand = root | bit_place, square_cand = root_cand*root_cand;
        if(square_cand <= n) root = root_cand;
        bit_place >>= 1;
    }
    return root;
}

static uint64_t icbrt(uint64_t n) {
    // modified code from hacker's delight, applying 64-bit specific fixes
    int64_t y = 0;
    for(int s = 63 ; s >= 0 ; s -= 3) {
        y = 2*y;
        int64_t b = 3*y*(y+1) + 1;
        if((n >> s) >= b) {
            n -= (b << s); ++y;
        }
    }
    return y;
}

// we need to memoize only lower levels of the tree
#define LPHI_MEMO_X 100000LL
#define LPHI_MEMO_A 100LL
static int64_t _lphi_memo[LPHI_MEMO_X+1][LPHI_MEMO_A+1] = {};

static int64_t legendre_phi(int64_t x, int64_t a) { assert(a < SIEVE_PRIME_COUNT);
    if(a == 1) return (x+1)/2; // odd numbers

    const bool should_memo = x <= LPHI_MEMO_X && a <= LPHI_MEMO_A;
    if(should_memo && _lphi_memo[x][a]) return _lphi_memo[x][a];

    // do not forget that in math we count primes from 1, but in prime array we count from 0
    const int64_t p = _sieve_prime[a-1];
    const int64_t t1 = legendre_phi(x, a-1);                // not using p[1],...,p[a-1]
    const int64_t t2 = x >= p ? legendre_phi(x/p, a-1) : 0; // not using p[1],...,p[a-1], but uses p[a]
    const int64_t phi = t1 - t2; if(should_memo) _lphi_memo[x][a] = phi;

    return phi;
}

static int64_t prime_pi_lehmer(int64_t N) {
    if(N <= SIEVE_MAX_PRIME) {
        const int idx = lower_bound(SIEVE_PRIME_COUNT, _sieve_prime, N); assert(idx < SIEVE_PRIME_COUNT);
        return idx + (_sieve_prime[idx] == N ? 1 : 0);
    }
    const int64_t N_2 = isqrt(N), a = prime_pi_lehmer(isqrt(N_2)), b = prime_pi_lehmer(N_2), c = prime_pi_lehmer(icbrt(N));
    int64_t ret = legendre_phi(N,a) + ((b+a-2)*(b-a+1)) / 2;
    for(int64_t i = a+1 ; i <= b ; ++i)
        ret -= prime_pi_lehmer(N/_sieve_prime[i-1]);
    for(int64_t i = a+1 ; i <= c ; ++i) {
        const int64_t pi = _sieve_prime[i-1], bi = prime_pi_lehmer(isqrt(N/pi));
        for(int64_t j = i ; j <= bi ; ++j)
            ret -= (prime_pi_lehmer(N/(pi*_sieve_prime[j-1])) - (j-1));
    }
    return ret;
}


int main() {
    generate_primes();

    int64_t N; scanf("%" PRId64 "\n", &N);

    int64_t count = 0;

    for(int i = 0 ; i < SIEVE_PRIME_COUNT ; ++i) {
        const int64_t p = _sieve_prime[i]; if(p*p*p > N) break;
        ++count;
    }

    for(int i = 0 ; i < SIEVE_PRIME_COUNT ; ++i) {
        const int64_t p = _sieve_prime[i]; if(p*p > N) break;
        const int64_t ppi = prime_pi_lehmer(N/p);
        if(ppi <= (i+1)) break;
        count += ppi - (i+1);   // do not forget that in math we count primes from 1, but in prime array we count from 0
    }

    printf("%" PRId64 "\n", count);
    return 0;
}
